diff --git a/kernel/src/proc/dump.rs b/kernel/src/proc/dump.rs
new file mode 100644
index 0000000..5c10008
--- /dev/null
+++ b/kernel/src/proc/dump.rs
@@ -0,0 +1,236 @@
+//! Formatted UART dump of the populated process and privilege tables.
+//!
+//! The slice-2.2 milestone: after `proc::init()`, the kernel writes this
+//! tabular view to the console so the operator can confirm the boot image
+//! materialized correctly. Output style matches the spirit of the existing
+//! exception-entry decode in `arch::aarch64::exception` (compact columns,
+//! mnemonic decode of flag bits).
+
+use core::fmt::{self, Write};
+use core::sync::atomic::Ordering;
+
+use arrayvec::ArrayString;
+
+use super::flags::{
+    BILLABLE, PREEMPTIBLE, ROOT_SYS_PROC, RTS_BOOTINHIBIT, RTS_NO_ENDPOINT, RTS_NO_PRIV,
+    RTS_PAGEFAULT, RTS_PREEMPTED, RTS_PROC_STOP, RTS_RECEIVING, RTS_SENDING, RTS_SIGNALED,
+    RTS_SIG_PENDING, RTS_SLOT_FREE, RTS_VMINHIBIT, SYS_PROC, VM_SYS_PROC,
+};
+use super::priv_struct::Priv;
+use super::proc_struct::Proc;
+use super::table::{n_image_slots, n_proc_slots, priv_table_ref, proc_table_ref};
+
+const NAME_WIDTH: usize = 16;
+const RTS_WIDTH: usize = 24;
+const PRIV_FLAGS_WIDTH: usize = 24;
+
+/// Dump the populated process + privilege tables to `out`.
+///
+/// SAFETY-adjacent: takes shared references to the static tables; callers
+/// must ensure no exclusive borrow is live for the call. Slice 2.2 invokes
+/// this once after `proc::init()` returns and never re-enters init, so the
+/// requirement is trivially met.
+pub fn dump_tables<W: Write>(out: &mut W) -> fmt::Result {
+    // SAFETY: single-threaded boot context; `proc::init()` has returned, so
+    // no `&mut` reference into PROC_TABLE / PRIV_TABLE is live.
+    let procs = unsafe { proc_table_ref() };
+    let privs = unsafe { priv_table_ref() };
+
+    let active = procs.iter().filter(|p| !is_free(p)).count();
+    writeln!(
+        out,
+        "Process table ({} slots, {} active):",
+        n_proc_slots(),
+        active,
+    )?;
+    writeln!(
+        out,
+        "   nr  endpoint    {:<NAME_WIDTH$}  priv  {:<RTS_WIDTH$}  prio  q_ms",
+        "name", "rts",
+    )?;
+    for p in procs.iter() {
+        if is_free(p) {
+            continue;
+        }
+        dump_proc(out, p)?;
+    }
+
+    let used = privs.iter().filter(|pr| pr.proc_nr.is_some()).count();
+    writeln!(out)?;
+    writeln!(
+        out,
+        "Privilege table ({} used / {} total, image = {}):",
+        used,
+        privs.len(),
+        n_image_slots(),
+    )?;
+    writeln!(
+        out,
+        "   id  proc-nr  {:<PRIV_FLAGS_WIDTH$}  trap    ipc_to                  k_call",
+        "flags",
+    )?;
+    for pr in privs.iter() {
+        if pr.proc_nr.is_none() {
+            continue;
+        }
+        dump_priv(out, pr)?;
+    }
+
+    Ok(())
+}
+
+fn is_free(p: &Proc) -> bool {
+    p.rts_flags.load(Ordering::Relaxed) & RTS_SLOT_FREE != 0
+}
+
+fn dump_proc<W: Write>(out: &mut W, p: &Proc) -> fmt::Result {
+    writeln!(
+        out,
+        "  {:>3}  {:#010x}  {:<NAME_WIDTH$}  {:>4}  {:<RTS_WIDTH$}  {:>4}  {:>4}",
+        p.nr.get(),
+        p.endpoint as u32,
+        NameDecoder(&p.name),
+        PrivIdDisplay(p.priv_id),
+        RtsDecoder(p.rts_flags.load(Ordering::Relaxed)),
+        p.priority,
+        p.quantum_ms,
+    )
+}
+
+fn dump_priv<W: Write>(out: &mut W, pr: &Priv) -> fmt::Result {
+    let proc_nr = pr.proc_nr.map(|n| n.get()).unwrap_or(i32::MIN);
+    writeln!(
+        out,
+        "  {:>3}  {:>7}  {:<PRIV_FLAGS_WIDTH$}  {:#06x}  {:#010x} {:#010x}  {:#010x}",
+        pr.id.get(),
+        proc_nr,
+        PrivFlagDecoder(pr.flags),
+        pr.trap_mask,
+        pr.ipc_to[0],
+        pr.ipc_to[1],
+        pr.k_call_mask[0],
+    )
+}
+
+// ---------------------------------------------------------------------------
+// Width-aware Display wrappers.
+//
+// `f.pad(s)` is the supported path for honouring `{:<width$}` from a custom
+// Display impl: render into a fixed-size stack buffer, then hand the buffer
+// to the formatter. ArrayString here keeps the dump zero-alloc.
+// ---------------------------------------------------------------------------
+
+const RENDER_BUF: usize = 96;
+
+fn render_padded<F>(f: &mut fmt::Formatter<'_>, render: F) -> fmt::Result
+where
+    F: FnOnce(&mut ArrayString<RENDER_BUF>) -> fmt::Result,
+{
+    let mut buf: ArrayString<RENDER_BUF> = ArrayString::new();
+    // Ignore overflow — the buffer is sized to fit every label we emit; if a
+    // future label trips this, the truncated output still lands but signals
+    // we need a bigger buffer.
+    let _ = render(&mut buf);
+    f.pad(buf.as_str())
+}
+
+struct NameDecoder<'a>(&'a [u8]);
+
+impl<'a> fmt::Display for NameDecoder<'a> {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        render_padded(f, |buf| {
+            for &b in self.0 {
+                if b == 0 {
+                    break;
+                }
+                let c = if b.is_ascii() && !b.is_ascii_control() {
+                    b as char
+                } else {
+                    '?'
+                };
+                let _ = buf.try_push(c);
+            }
+            Ok(())
+        })
+    }
+}
+
+struct PrivIdDisplay(Option<minix4_kernel_shared::PrivId>);
+
+impl fmt::Display for PrivIdDisplay {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        render_padded(f, |buf| match self.0 {
+            Some(id) => write!(buf, "{}", id.get()),
+            None => buf.write_str("-"),
+        })
+    }
+}
+
+struct RtsDecoder(u32);
+
+impl fmt::Display for RtsDecoder {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        let v = self.0;
+        render_padded(f, |buf| {
+            if v == 0 {
+                return buf.write_str("RUN");
+            }
+            let mut first = true;
+            let pairs: [(u32, &str); 12] = [
+                (RTS_PROC_STOP, "STOP"),
+                (RTS_SENDING, "SEND"),
+                (RTS_RECEIVING, "RECV"),
+                (RTS_SIGNALED, "SIGD"),
+                (RTS_SIG_PENDING, "SIGP"),
+                (RTS_NO_PRIV, "NOPRIV"),
+                (RTS_NO_ENDPOINT, "NOEPT"),
+                (RTS_VMINHIBIT, "VMINH"),
+                (RTS_PAGEFAULT, "PGFLT"),
+                (RTS_PREEMPTED, "PREEMPT"),
+                (RTS_BOOTINHIBIT, "BOOTINH"),
+                (RTS_SLOT_FREE, "FREE"),
+            ];
+            for (bit, name) in pairs {
+                if v & bit != 0 {
+                    if !first {
+                        buf.write_char('|')?;
+                    }
+                    buf.write_str(name)?;
+                    first = false;
+                }
+            }
+            Ok(())
+        })
+    }
+}
+
+struct PrivFlagDecoder(u16);
+
+impl fmt::Display for PrivFlagDecoder {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        let v = self.0;
+        render_padded(f, |buf| {
+            if v == 0 {
+                return buf.write_str("-");
+            }
+            let mut first = true;
+            let pairs: [(u16, &str); 5] = [
+                (SYS_PROC, "SYS"),
+                (PREEMPTIBLE, "PREEMPT"),
+                (BILLABLE, "BILL"),
+                (ROOT_SYS_PROC, "ROOT"),
+                (VM_SYS_PROC, "VMSYS"),
+            ];
+            for (bit, name) in pairs {
+                if v & bit != 0 {
+                    if !first {
+                        buf.write_char('|')?;
+                    }
+                    buf.write_str(name)?;
+                    first = false;
+                }
+            }
+            Ok(())
+        })
+    }
+}
diff --git a/kernel/src/proc/flags.rs b/kernel/src/proc/flags.rs
new file mode 100644
index 0000000..804fb7a
--- /dev/null
+++ b/kernel/src/proc/flags.rs
@@ -0,0 +1,122 @@
+// Many of these constants are defined now so that the slice-2.5 IPC code and
+// slice-2.6 kernel-call dispatch can land without churning this module
+// again. They become live as later slices consume them.
+#![allow(dead_code)]
+
+//! Kernel-internal flag bits for [`Proc`] and [`Priv`].
+//!
+//! [`Proc`]: super::Proc
+//! [`Priv`]: super::Priv
+//!
+//! Values mirror MINIX 3 `kernel/proc.h` (RTS / MF) and `include/minix/const.h`
+//! (PREEMPTIBLE / BILLABLE / …) so the bit semantics are recognizable. None
+//! of these constants belong on the IPC wire — userspace never sees them —
+//! so they live in the kernel crate rather than in `kernel-shared`.
+//!
+//! MINIX 4 drops a few MINIX 3 flags that are not relevant to the port:
+//! `LU_SYS_PROC` (no live update), `MF_FLUSH_TLB` / `MF_SPROF_SEEN` (no SMP,
+//! no profiling), `MF_SC_*` (no syscall tracing).
+
+use minix4_kernel_shared::ipc_const::{RECEIVE, SENDREC};
+
+// ---------------------------------------------------------------------------
+// Run-time state flags (`Proc::rts_flags`).
+//
+// A process is runnable iff `rts_flags == 0`. Each bit identifies a distinct
+// reason the kernel is keeping the process off the run queue; clearing all
+// reasons makes the process runnable again.
+// ---------------------------------------------------------------------------
+
+/// Process-table slot is free.
+pub const RTS_SLOT_FREE: u32 = 0x0_0001;
+/// Process has been explicitly stopped.
+pub const RTS_PROC_STOP: u32 = 0x0_0002;
+/// Blocked trying to `SEND`.
+pub const RTS_SENDING: u32 = 0x0_0004;
+/// Blocked trying to `RECEIVE`.
+pub const RTS_RECEIVING: u32 = 0x0_0008;
+/// A kernel signal has arrived for this process.
+pub const RTS_SIGNALED: u32 = 0x0_0010;
+/// Signal handling is in progress.
+pub const RTS_SIG_PENDING: u32 = 0x0_0020;
+/// Process is being traced (debugger / ptrace).
+pub const RTS_P_STOP: u32 = 0x0_0040;
+/// Forked system process awaiting privilege assignment.
+pub const RTS_NO_PRIV: u32 = 0x0_0080;
+/// Process cannot send or receive — no valid endpoint.
+pub const RTS_NO_ENDPOINT: u32 = 0x0_0100;
+/// Awaiting VM to set up page tables.
+pub const RTS_VMINHIBIT: u32 = 0x0_0200;
+/// Unhandled page fault pending.
+pub const RTS_PAGEFAULT: u32 = 0x0_0400;
+/// Originator of a VM memory request, waiting on resolution.
+pub const RTS_VMREQUEST: u32 = 0x0_0800;
+/// Target of a VM memory request, helping the originator.
+pub const RTS_VMREQTARGET: u32 = 0x0_1000;
+/// Preempted by a higher-priority process — re-enqueue at the front.
+pub const RTS_PREEMPTED: u32 = 0x0_4000;
+/// Quantum exhausted — re-enqueue at the back of the run queue.
+pub const RTS_NO_QUANTUM: u32 = 0x0_8000;
+/// Awaiting VM to finish boot-time setup.
+pub const RTS_BOOTINHIBIT: u32 = 0x1_0000;
+
+// ---------------------------------------------------------------------------
+// Miscellaneous flags (`Proc::misc_flags`).
+//
+// These do NOT block scheduling; they are status bits the kernel consults
+// during IPC, signal delivery, and FPU handling.
+// ---------------------------------------------------------------------------
+
+pub const MF_REPLY_PEND: u32 = 0x0_0001;
+pub const MF_VIRT_TIMER: u32 = 0x0_0002;
+pub const MF_PROF_TIMER: u32 = 0x0_0004;
+pub const MF_KCALL_RESUME: u32 = 0x0_0008;
+pub const MF_DELIVERMSG: u32 = 0x0_0040;
+pub const MF_SIG_DELAY: u32 = 0x0_0080;
+pub const MF_FPU_INITIALIZED: u32 = 0x0_1000;
+pub const MF_SENDING_FROM_KERNEL: u32 = 0x0_2000;
+pub const MF_CONTEXT_SET: u32 = 0x0_4000;
+pub const MF_SENDA_VM_MISS: u32 = 0x2_0000;
+pub const MF_STEP: u32 = 0x4_0000;
+pub const MF_MSGFAILED: u32 = 0x8_0000;
+pub const MF_NICED: u32 = 0x10_0000;
+
+// ---------------------------------------------------------------------------
+// Privilege flags (`Priv::flags`). 16-bit to match `Priv`'s field width.
+// ---------------------------------------------------------------------------
+
+/// Process is preemptible (kernel tasks are not).
+pub const PREEMPTIBLE: u16 = 0x002;
+/// CPU time is charged to this process.
+pub const BILLABLE: u16 = 0x004;
+/// Privilege ID was assigned dynamically (not from the boot image).
+pub const DYN_PRIV_ID: u16 = 0x008;
+/// System process — owns its own [`Priv`] slot.
+///
+/// [`Priv`]: super::Priv
+pub const SYS_PROC: u16 = 0x010;
+/// Privilege subsystem checks I/O port access requests against `Priv::io_ranges`.
+pub const CHECK_IO_PORT: u16 = 0x020;
+/// Privilege subsystem checks IRQ assignments against `Priv::irqs`.
+pub const CHECK_IRQ: u16 = 0x040;
+/// Privilege subsystem checks VM memory-range requests against `Priv::mem_ranges`.
+pub const CHECK_MEM: u16 = 0x080;
+/// Root system process (the reincarnation server, RS).
+pub const ROOT_SYS_PROC: u16 = 0x100;
+/// VM system process — gets the dedicated VM privilege role.
+pub const VM_SYS_PROC: u16 = 0x200;
+/// Restarted system process (set on respawn).
+pub const RST_SYS_PROC: u16 = 0x800;
+
+// ---------------------------------------------------------------------------
+// Trap masks (`Priv::trap_mask`). Bit `i` allows IPC primitive `i`.
+// ---------------------------------------------------------------------------
+
+/// Kernel-task trap mask — no IPC traps allowed (HARDWARE, IDLE, ASYNCM).
+pub const TSK_T: u16 = 0;
+/// "Constrained" kernel-task trap mask — only `RECEIVE` allowed (CLOCK, SYSTEM).
+pub const CSK_T: u16 = 1 << RECEIVE;
+/// User-process trap mask — only `SENDREC` allowed.
+pub const USR_T: u16 = 1 << SENDREC;
+/// System-server trap mask — all IPC primitives allowed.
+pub const SRV_T: u16 = !0;
