1299	+
1300	+/// SAFETY: caller must ensure no other reference into `PRIV_TABLE` exists.
1301	+pub(crate) unsafe fn priv_slot_mut(id: PrivId) -> Option<&'static mut Priv> {
1302	+    let idx = priv_index(id)?;
1303	+    // SAFETY: `idx` is in-range; single-threaded boot context.
1304	+    let arr = unsafe { &mut *PRIV_TABLE.0.get() };
1305	+    Some(&mut arr[idx])
1306	+}
1307	+
1308	+/// SAFETY: caller must ensure no exclusive reference into `PRIV_TABLE` exists.
1309	+pub(crate) unsafe fn priv_table_ref() -> &'static [Priv; NR_SYS_PROCS] {
1310	+    // SAFETY: single-threaded boot context.
1311	+    unsafe { &*PRIV_TABLE.0.get() }
1312	+}
1313	+
1314	+// ---------------------------------------------------------------------------
1315	+// Boot-time population.
1316	+// ---------------------------------------------------------------------------
1317	+
1318	+/// Populate `PROC_TABLE` and `PRIV_TABLE` from `IMAGE`.
1319	+///
1320	+/// Called once from `kmain` during boot. Idempotent in practice (re-running
1321	+/// would overwrite the same slots with the same data), but slice 2.4's
1322	+/// scheduler will assume one-shot init — do not call twice.
1323	+pub fn init() {
1324	+    init_empty_slots();
1325	+    init_boot_image();
1326	+}
1327	+
1328	+fn init_empty_slots() {
1329	+    // Give every slot a valid (nr, endpoint) so that index-based traversal
1330	+    // never sees a stale zero `nr` after `Proc::EMPTY` initialization.
1331	+    for i in 0..N_PROC_SLOTS {
1332	+        let nr = ProcNr::new(i as i32 - NR_TASKS as i32);
1333	+        // SAFETY: index in-range; single-threaded boot context; no other
1334	+        // references into PROC_TABLE exist at this point in `init`.
1335	+        let p = unsafe { proc_slot_mut(nr) }.expect("proc index in range");
1336	+        p.nr = nr;
1337	+        p.endpoint = boot_endpoint(nr);
1338	+        // EMPTY left rts_flags = RTS_SLOT_FREE — leave it that way.
1339	+    }
1340	+
1341	+    for i in 0..NR_SYS_PROCS {
1342	+        // SAFETY: index in-range; single-threaded boot context.
1343	+        let pr = unsafe { priv_slot_mut(PrivId::new(i as u16)) }
1344	+            .expect("priv index in range");
1345	+        pr.id = PrivId::new(i as u16);
1346	+    }
1347	+}
1348	+
1349	+fn init_boot_image() {
1350	+    // Active priv-slot count after population — the IPC bitmap for SRV_T
1351	+    // entries needs to enumerate every active slot.
1352	+    let n_active = N_IMAGE as u16;
1353	+
1354	+    for (slot, entry) in IMAGE.iter().enumerate() {
1355	+        let priv_id = PrivId::new(slot as u16);
1356	+        populate_priv(priv_id, entry, n_active);
1357	+        populate_proc(priv_id, entry);
1358	+    }
1359	+}
1360	+
1361	+fn populate_priv(id: PrivId, entry: &BootEntry, n_active: u16) {
1362	+    // SAFETY: priv index < NR_SYS_PROCS; single-threaded boot context; no
1363	+    // overlapping reference into PRIV_TABLE held across the call.
1364	+    let pr = unsafe { priv_slot_mut(id) }.expect("priv slot in range");
1365	+    pr.id = id;
1366	+    pr.proc_nr = Some(entry.nr);
1367	+    pr.flags = entry.priv_flags;
1368	+    pr.trap_mask = entry.trap_mask;
1369	+
1370	+    if entry.trap_mask == SRV_T {
1371	+        // SRV_T privs can send to every active slot. Set bits [0, n_active).
1372	+        fill_bits(&mut pr.ipc_to, n_active as usize);
1373	+        // SRV_T privs can issue every Phase-2 kernel call.
1374	+        fill_bits(&mut pr.k_call_mask, NR_KERN_CALLS_PHASE2);
1375	+    }
1376	+    // Kernel-task slots leave ipc_to and k_call_mask zeroed.
1377	+
1378	+    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
1379	+    pr.notify_pending.fill(0);
1380	+    pr.asyn_pending.fill(0);
1381	+}
1382	+
1383	+fn populate_proc(priv_id: PrivId, entry: &BootEntry) {
1384	+    // SAFETY: proc index in-range; single-threaded boot context; no
1385	+    // overlapping reference into PROC_TABLE held across the call.
1386	+    let p = unsafe { proc_slot_mut(entry.nr) }.expect("proc slot in range");
1387	+    p.priv_id = Some(priv_id);
1388	+    p.priority = entry.priority;
1389	+    p.quantum_ms = entry.quantum_ms;
1390	+    p.quantum_left = entry.quantum_ms as u64;
1391	+    p.endpoint = boot_endpoint(entry.nr);
1392	+    p.nr = entry.nr;
1393	+
1394	+    // Copy name into the fixed-width field (truncates silently at PROC_NAME_LEN).
1395	+    let n = core::cmp::min(entry.name.len(), PROC_NAME_LEN - 1);
1396	+    p.name[..n].copy_from_slice(&entry.name[..n]);
1397	+    p.name[n..].fill(0);
1398	+
1399	+    let rts = if entry.runnable { 0 } else { RTS_NO_PRIV };
1400	+    p.rts_flags
1401	+        .store(rts, core::sync::atomic::Ordering::Relaxed);
1402	+}
1403	+
1404	+/// Set the lowest `n` bits in a `u32` bitmap.
1405	+fn fill_bits(map: &mut [u32], n: usize) {
1406	+    for i in 0..n {
1407	+        let word = i / 32;
1408	+        let bit = i % 32;
1409	+        if word < map.len() {
1410	+            map[word] |= 1 << bit;
1411	+        }
1412	+    }
1413	+}
1414	+
1415	+// Compile-time sanity that the bitmap sizing came out as expected.
1416	+const _: () = assert!(IPC_MAP_CHUNKS == 2);
1417	+const _: () = assert!(K_CALL_MASK_CHUNKS == 1);
1418	+
1419	+/// Number of slots in `PROC_TABLE` (for the dump helper).
1420	+pub const fn n_proc_slots() -> usize {
1421	+    N_PROC_SLOTS
1422	+}
1423	+
1424	+/// Number of slots in `IMAGE` (for the dump helper).
1425	+pub const fn n_image_slots() -> usize {
1426	+    N_IMAGE
1427	+}
